mapper.select:
        SELECT COUNT(*)

        FROM public.crms_trans_rqst AS rqst

		LEFT JOIN (
			SELECT crms_user.user_id,
					crms_user.user_nm
			FROM xeus.mt_usr_desc AS crms_user
			LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no
		)  AS reqst_id_rel         ON reqst_id_rel.user_id = rqst.reqst_id
		LEFT JOIN xeus.mt_cmm_cde   AS proc_stat_cd_rel     ON proc_stat_cd_rel.grp_cde = 'C52' AND proc_stat_cd_rel.cde_cde = rqst.proc_stat_cd
		LEFT JOIN xeus.mt_cmm_cde   AS req_gbn_cd_rel       ON req_gbn_cd_rel.grp_cde = 'C58' AND req_gbn_cd_rel.cde_cde = rqst.req_gbn_cd




                AND rqst.mgr_seq::text LIKE '%'||#{mgrSeq}||'%'



                AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'



                AND reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'



                AND rqst.reqst_dat = #{reqstDat}



                AND rqst.cctv_list = #{cctvList}



                AND rqst.proc_stat_cd = #{procStatCd}



                AND rqst.req_gbn_cd = #{reqGbnCd}



                AND rqst.reqst_dat  >=  #{startDat}



                AND rqst.reqst_dat  <=  #{endDat}

        SELECT rqst.mgr_seq AS mgr_seq, rqst.reqst_id AS reqst_id, reqst_id_rel.user_nm AS reqst_id_rel_cde_nm, rqst.reqst_dat AS reqst_dat
			, rqst.cctv_list AS cctv_list, proc_stat_cd_rel.cde_nm AS proc_stat_cd_rel_cde_nm
			, req_gbn_cd_rel.cde_nm AS req_gbn_cd_rel_cde_nm

		FROM public.crms_trans_rqst AS rqst

		LEFT JOIN (
			SELECT crms_user.user_id,
					crms_user.user_nm
			FROM xeus.mt_usr_desc AS crms_user
			LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no
		)  AS reqst_id_rel         ON reqst_id_rel.user_id = rqst.reqst_id
		LEFT JOIN xeus.mt_cmm_cde   AS proc_stat_cd_rel     ON proc_stat_cd_rel.grp_cde = 'C52' AND proc_stat_cd_rel.cde_cde = rqst.proc_stat_cd
		LEFT JOIN xeus.mt_cmm_cde   AS req_gbn_cd_rel       ON req_gbn_cd_rel.grp_cde = 'C58' AND req_gbn_cd_rel.cde_cde = rqst.req_gbn_cd




                AND rqst.mgr_seq::text LIKE '%'||#{mgrSeq}||'%'



                AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'



                AND reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'



                AND rqst.reqst_dat = #{reqstDat}



                AND rqst.cctv_list = #{cctvList}



                AND rqst.proc_stat_cd = #{procStatCd}



                AND rqst.req_gbn_cd = #{reqGbnCd}



                AND rqst.reqst_dat  >=  #{startDat}



                AND rqst.reqst_dat  <=  #{endDat}






                ${sortCol} ${sortTyp}


                rqst.mgr_seq DESC




            LIMIT ${limit} OFFSET ${offset}
